namespace sv_98814ba202fe4041ab5cf8b47371ce12.Client.Models;

public class Shipment
{
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public string Description { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Models;

namespace sv_98814ba202fe4041ab5cf8b47371ce12.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Models;

namespace sv_98814ba202fe4041ab5cf8b47371ce12.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await httpClient.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException(
            $"Shipment '{trackingNumber}' not found.");
    }
}

using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Models;
using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Services;

namespace sv_98814ba202fe4041ab5cf8b47371ce12.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Shipments = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 2, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 24, 9, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 24, 14, 15, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Arrived at hub", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 25, 8, 45, 0, DateTimeKind.Utc) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 26, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTime(2026, 5, 22, 10, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 23, 6, 20, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 26, 8, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 26, 11, 35, 0, DateTimeKind.Utc) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 27, 7, 0, 0, DateTimeKind.Utc) },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (!Shipments.TryGetValue(trackingNumber, out var shipment))
        {
            throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
        }

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Models
@using sv_98814ba202fe4041ab5cf8b47371ce12.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (isLoading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@errorMessage</p>
        <button class="btn btn-primary" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (shipment is not null)
{
    <h3>Shipment @shipment.TrackingNumber</h3>

    <dl>
        <dt>Status</dt>
        <dd>@shipment.Status</dd>

        <dt>Current Location</dt>
        <dd>@shipment.Location</dd>

        <dt>Estimated Delivery</dt>
        <dd>@(shipment.EstimatedDelivery?.ToString("f") ?? "Unknown")</dd>
    </dl>

    @if (shipment.StatusUpdates.Count > 0)
    {
        <h4>Tracking History</h4>
        <table class="table">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Location</th>
                    <th>Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? shipment;
    private bool isLoading;
    private string? errorMessage;
    private CancellationTokenSource? cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var token = cts.Token;

        shipment = null;
        errorMessage = null;
        isLoading = true;

        try
        {
            shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, token);
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently abandon.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        cts?.Cancel();
        cts?.Dispose();
    }
}

